const LOG_THROTTLE_WINDOW_MS = Math.max(1000, Number(process.env.LOG_THROTTLE_WINDOW_MS || 10000));
const LOG_THROTTLE_MAX_PER_SIGNATURE = Math.max(3, Number(process.env.LOG_THROTTLE_MAX_PER_SIGNATURE || 12));
const LOG_THROTTLE_SUMMARY_INTERVAL_MS = Math.max(5000, Number(process.env.LOG_THROTTLE_SUMMARY_INTERVAL_MS || 30000));
const ORIGINAL_CONSOLE_METHODS = {
    log: console.log.bind(console),
    info: (console.info || console.log).bind(console),
    warn: console.warn.bind(console),
    error: console.error.bind(console)
};
const logThrottleState = new Map();
let logThrottleLastSummaryAt = 0;
const NOISY_SESSION_LOG_PATTERNS = [
    /closing session/i,
    /session closed/i,
    /pendingprekey/i,
    /currentratchet/i,
    /ephemeralkeypair/i,
    /basekeytype/i,
    /\b_chains\b/i
];

function shouldDropLogEntry(args = []) {
    const serialized = args.slice(0, 6).map((item) => serializeLogChunkForThrottle(item)).join(' | ');
    return NOISY_SESSION_LOG_PATTERNS.some((pattern) => pattern.test(serialized));
}

function serializeLogChunkForThrottle(value, depth = 0) {
    if (value == null) return String(value);
    if (Buffer.isBuffer(value)) return `<Buffer ${value.length} bytes>`;
    if (value instanceof Error) return value.stack || value.message || String(value);
    const valueType = typeof value;
    if (valueType === 'string') return value;
    if (valueType === 'number' || valueType === 'boolean' || valueType === 'bigint') return String(value);
    if (valueType === 'function') return `[Function ${value.name || 'anonymous'}]`;
    if (depth >= 2) return '[Object]';
    if (Array.isArray(value)) {
        return `[${value.slice(0, 8).map((item) => serializeLogChunkForThrottle(item, depth + 1)).join(', ')}${value.length > 8 ? ', …' : ''}]`;
    }
    const cloned = {};
    let count = 0;
    for (const [key, item] of Object.entries(value)) {
        if (count >= 12) {
            cloned.__truncated__ = true;
            break;
        }
        cloned[key] = Buffer.isBuffer(item)
            ? `<Buffer ${item.length} bytes>`
            : (item instanceof Error ? (item.stack || item.message || String(item)) : (typeof item === 'object' && item !== null ? serializeLogChunkForThrottle(item, depth + 1) : item));
        count += 1;
    }
    try {
        return JSON.stringify(cloned);
    } catch (_) {
        return '[Unserializable Object]';
    }
}

function flushSuppressedLogsSummary(force = false) {
    const now = Date.now();
    if (!force && now - logThrottleLastSummaryAt < LOG_THROTTLE_SUMMARY_INTERVAL_MS) return;
    logThrottleLastSummaryAt = now;
    let suppressedTotal = 0;
    for (const [signature, entry] of Array.from(logThrottleState.entries())) {
        if (now - entry.startedAt > LOG_THROTTLE_WINDOW_MS) {
            suppressedTotal += Number(entry.suppressed || 0);
            logThrottleState.delete(signature);
        }
    }
    if (suppressedTotal > 0) {
        ORIGINAL_CONSOLE_METHODS.warn(`[log-throttle] suppressed ${suppressedTotal} repeated log entries in the last window`);
    }
}

function installConsoleRateLimiter() {
    if (console.__rateLimiterInstalled) return;
    for (const method of ['log', 'info', 'warn', 'error']) {
        console[method] = (...args) => {
            try {
                if (shouldDropLogEntry(args)) return;
                const now = Date.now();
                const signature = `${method}:${args.slice(0, 3).map((item) => serializeLogChunkForThrottle(item)).join(' | ').slice(0, 600)}`;
                const current = logThrottleState.get(signature);
                if (!current || now - current.startedAt > LOG_THROTTLE_WINDOW_MS) {
                    if (current?.suppressed) {
                        ORIGINAL_CONSOLE_METHODS.warn(`[log-throttle] ${current.suppressed} duplicate entries skipped for ${method}`);
                    }
                    logThrottleState.set(signature, { count: 1, suppressed: 0, startedAt: now });
                    ORIGINAL_CONSOLE_METHODS[method](...args.map((item) => serializeLogChunkForThrottle(item)));
                    flushSuppressedLogsSummary(false);
                    return;
                }
                current.count += 1;
                if (current.count <= LOG_THROTTLE_MAX_PER_SIGNATURE) {
                    ORIGINAL_CONSOLE_METHODS[method](...args.map((item) => serializeLogChunkForThrottle(item)));
                } else {
                    current.suppressed += 1;
                }
                flushSuppressedLogsSummary(false);
            } catch (_) {
                ORIGINAL_CONSOLE_METHODS[method](...args);
            }
        };
    }
    console.__rateLimiterInstalled = true;
}

installConsoleRateLimiter();
preloadLegacyProjectModules();

const EMBEDDED_PAIR_CODE_BRIDGE = (() => {
    try {
        "use strict";

        const fs = require("fs");
        const path = require("path");
        let TelegramBot = null;
        try {
            TelegramBot = require("node-telegram-bot-api");
        } catch (_) {
            TelegramBot = null;
        }

        const BASE_DIR = __dirname;
        const ENV_PATH = path.join(BASE_DIR, ".env");
        const SETTINGS_PATH = path.join(BASE_DIR, "bot_settings.json");
        const DEFAULT_REQUEST_TIMEOUT = parseInt(process.env.PAIR_CODE_TIMEOUT || "45", 10) * 1000;

        function loadDotenvFile(filePath) {
            if (!fs.existsSync(filePath)) return;

            const content = fs.readFileSync(filePath, "utf8");
            for (const rawLine of content.split(/\r?\n/)) {
                const line = rawLine.trim();
                if (!line || line.startsWith("#") || !line.includes("=")) continue;

                const [rawKey, ...rest] = line.split("=");
                const key = String(rawKey || "").trim();
                const value = rest.join("=").trim().replace(/^['"]|['"]$/g, "");

                if (key && !(key in process.env)) {
                    process.env[key] = value;
                }
            }
        }

        function parseBool(value, defaultValue = false) {
            if (typeof value === "boolean") return value;
            if (value === null || value === undefined) return defaultValue;
            if (typeof value === "number") return Boolean(value);

            const normalized = String(value).trim().toLowerCase();
            if (["1", "true", "yes", "on", "enabled", "enable"].includes(normalized)) return true;
            if (["0", "false", "no", "off", "disabled", "disable"].includes(normalized)) return false;
            return defaultValue;
        }

        function escapeHtml(value) {
            return String(value)
                .replace(/&/g, "&amp;")
                .replace(/</g, "&lt;")
                .replace(/>/g, "&gt;")
                .replace(/\"/g, "&quot;")
                .replace(/'/g, "&#39;");
        }

        loadDotenvFile(ENV_PATH);

        const BOT_TOKEN = String(process.env.BOT_TOKEN || "").trim();
        const parsedAdminId = parseInt(process.env.ADMIN_ID || "0", 10);
        const ADMIN_ID = Number.isNaN(parsedAdminId) ? 0 : parsedAdminId;

        const GREEN_API_BASE_URL = String(process.env.GREEN_API_BASE_URL || "https://api.green-api.com")
            .trim()
            .replace(/\/+$/, "");
        const GREEN_API_ID_INSTANCE = String(process.env.GREEN_API_ID_INSTANCE || "").trim();
        const GREEN_API_TOKEN_INSTANCE = String(process.env.GREEN_API_TOKEN_INSTANCE || "").trim();

        function getGreenApiAuthorizationUrl() {
            if (GREEN_API_ID_INSTANCE && GREEN_API_TOKEN_INSTANCE) {
                return `${GREEN_API_BASE_URL}/waInstance${GREEN_API_ID_INSTANCE}/getAuthorizationCode/${GREEN_API_TOKEN_INSTANCE}`;
            }
            return "";
        }

        const DEFAULT_PUBLIC_WEB_BASE_URL = String(process.env.DEFAULT_PUBLIC_BASE_URL || process.env.PUBLIC_BASE_URL || process.env.APP_URL || '').trim().replace(/\/+$/, '') || `http://127.0.0.1:${process.env.PORT || 3000}`;

        const DEFAULT_SETTINGS = {
            current_emoji: String(process.env.CURRENT_EMOJI || "🔥"),
            auto_reply_enabled: parseBool(process.env.AUTO_REPLY_ENABLED || "true", true),
            pair_code_api_url: String(process.env.PAIR_CODE_API_URL || process.env.PAIRING_API_URL || "").trim() || `${DEFAULT_PUBLIC_WEB_BASE_URL}/api/pairing`,
            pair_code_api_method: String(process.env.PAIR_CODE_API_METHOD || process.env.PAIRING_API_METHOD || "POST").trim().toUpperCase() || "POST",
            pair_code_api_token: String(process.env.PAIR_CODE_API_TOKEN || process.env.PAIRING_API_TOKEN || "").trim(),
            pair_code_api_number_field: String(process.env.PAIR_CODE_API_NUMBER_FIELD || process.env.PAIRING_API_NUMBER_FIELD || "phone").trim() || "phone",
        };

        const BOT_STATS = {
            startedAt: new Date(),
            totalUsers: new Set(),
            pairRequests: 0,
            pairSuccess: 0,
            pairFailed: 0,
        };

        const ADMIN_INPUT_FIELDS = {
            set_emoji: "current_emoji",
            set_api_url: "pair_code_api_url",
            set_api_token: "pair_code_api_token",
            set_api_method: "pair_code_api_method",
            set_number_field: "pair_code_api_number_field",
        };

        function normalizeSettings(data) {
            const output = { ...DEFAULT_SETTINGS, ...(data || {}) };

            output.pair_code_api_method = String(output.pair_code_api_method || "POST").trim().toUpperCase() || "POST";
            if (!["GET", "POST"].includes(output.pair_code_api_method)) {
                output.pair_code_api_method = "POST";
            }

            output.pair_code_api_number_field =
                String(output.pair_code_api_number_field || "phone").trim() || "phone";
            output.pair_code_api_url = String(output.pair_code_api_url || "").trim();
            output.pair_code_api_token = String(output.pair_code_api_token || "").trim();
            output.current_emoji = String(output.current_emoji || "🔥").trim().slice(0, 10) || "🔥";
            output.auto_reply_enabled = parseBool(output.auto_reply_enabled, true);

            return output;
        }

        function loadSettings() {
            try {
                if (!fs.existsSync(SETTINGS_PATH)) return normalizeSettings(DEFAULT_SETTINGS);
                const raw = fs.readFileSync(SETTINGS_PATH, "utf8");
                const parsed = JSON.parse(raw);
                return normalizeSettings(parsed);
            } catch (error) {
                console.error("Failed to load saved settings:", error);
                return normalizeSettings(DEFAULT_SETTINGS);
            }
        }

        let SETTINGS = loadSettings();

        function saveSettings() {
            SETTINGS = normalizeSettings(SETTINGS);
            fs.writeFileSync(SETTINGS_PATH, JSON.stringify(SETTINGS, null, 2), "utf8");
        }

        const userState = new Map();

        function getUserState(userId) {
            if (!userState.has(userId)) {
                userState.set(userId, {
                    awaitingPairNumber: false,
                    adminWaitingField: null,
                });
            }
            return userState.get(userId);
        }

        function registerUser(msgOrQuery) {
            const user = msgOrQuery?.from || msgOrQuery?.message?.from;
            if (user?.id) {
                BOT_STATS.totalUsers.add(user.id);
            }
        }

        function isAdmin(msgOrQuery) {
            const user = msgOrQuery?.from || msgOrQuery?.message?.from;
            return Boolean(user && ADMIN_ID && user.id === ADMIN_ID);
        }

        return {
            TelegramBot,
            BASE_DIR,
            ENV_PATH,
            SETTINGS_PATH,
            DEFAULT_REQUEST_TIMEOUT,
            BOT_TOKEN,
            ADMIN_ID,
            DEFAULT_SETTINGS,
            BOT_STATS,
            ADMIN_INPUT_FIELDS,
            loadDotenvFile,
            parseBool,
            escapeHtml,
            getGreenApiAuthorizationUrl,
            normalizeSettings,
            loadSettings,
            saveSettings,
            getUserState,
            registerUser,
            isAdmin,
            get settings() {
                return SETTINGS;
            },
            set settings(nextValue) {
                SETTINGS = normalizeSettings(nextValue);
            }
        };
    } catch (error) {
        console.error('Embedded pair-code bridge bootstrap error:', error.message || error);
        return {
            bootstrapError: String(error?.message || error || 'unknown_error')
        };
    }
})();

