function getImportedPhoneSettingsSeed(phone) {
    const normalized = normalizePhone(phone);
    if (normalized === IMPORTED_REDQUEEN_PHONE) {
        return JSON.parse(JSON.stringify(IMPORTED_REDQUEEN_PHONE_SETTINGS));
    }
    if (normalized === IMPORTED_OMAR_PHONE) {
        return JSON.parse(JSON.stringify(IMPORTED_OMAR_PHONE_SETTINGS));
    }
    return null;
}

function getImportedPhoneSettingsPassword(phone) {
    const normalized = normalizePhone(phone);
    if (normalized === IMPORTED_REDQUEEN_PHONE) return IMPORTED_REDQUEEN_PASSWORD;
    if (normalized === IMPORTED_OMAR_PHONE) return IMPORTED_OMAR_PASSWORD;
    return '';
}

