const PREFERRED_BROWSER_PROFILE = Object.freeze(['macOS', 'Safari', '17.4']);
const HEALTH_CHECK_INTERVAL_MS = Math.max(5000, Number(process.env.HEALTH_CHECK_INTERVAL_MS || 15000));
const CLIENT_STALE_AFTER_MS = Math.max(60000, Number(process.env.CLIENT_STALE_AFTER_MS || 180000));
const STATUS_INTERACTION_DELAY_MS = Math.max(0, Number(process.env.STATUS_INTERACTION_DELAY_MS || 250));
const SESSION_PING_INTERVAL_MS = Math.max(5000, Number(process.env.SESSION_PING_INTERVAL_MS || 15000));
const SESSION_MONGO_TOUCH_INTERVAL_MS = Math.max(60000, Number(process.env.SESSION_MONGO_TOUCH_INTERVAL_MS || 180000));
const RUNTIME_CLEANUP_INTERVAL_MS = Math.max(30000, Number(process.env.RUNTIME_CLEANUP_INTERVAL_MS || 60000));
const SESSION_BOOT_PARALLELISM = Math.max(1, Math.min(6, Number(process.env.SESSION_BOOT_PARALLELISM || 2)));
const MAX_PARALLEL_STATUS_JOBS_PER_PHONE = Math.max(1, Math.min(8, Number(process.env.MAX_PARALLEL_STATUS_JOBS_PER_PHONE || 3)));
const STATUS_EVENT_DEDUPE_TTL_MS = Math.max(30000, Number(process.env.STATUS_EVENT_DEDUPE_TTL_MS || 300000));
let sessionSupervisorStarted = false;
let lastRuntimeCleanupAt = 0;
const DATABASE_ENABLED = Boolean(MONGODB_URI);
let mongoConnectionPromise = null;
let mongoConnectionHooksInstalled = false;

process.on('unhandledRejection', (reason) => {
    console.error('Unhandled Promise Rejection:', reason?.stack || reason?.message || reason);
});

process.on('uncaughtException', (error) => {
    console.error('Uncaught Exception:', error?.stack || error?.message || error);
});


function getPreferredBrowserProfile() {
    return Array.isArray(PREFERRED_BROWSER_PROFILE) ? [...PREFERRED_BROWSER_PROFILE] : Browsers.macOS('Safari');
}

function ensureMongoConnectionHooks() {
    if (mongoConnectionHooksInstalled) return;
    mongoConnectionHooksInstalled = true;
}

async function connectToDatabase() {
    if (!DATABASE_ENABLED) return null;

    if (!mongoConnectionPromise) {
        mongoConnectionPromise = (async () => {
            ensureMongoConnectionHooks();
            const client = new MongoClient(MONGODB_URI, {
                appName: 'KnightBot-MD',
                serverSelectionTimeoutMS: MONGO_CONNECT_TIMEOUT_MS,
                connectTimeoutMS: MONGO_CONNECT_TIMEOUT_MS,
                maxPoolSize: 10,
                retryWrites: true
            });

            await client.connect();
            const db = client.db(DEFAULT_MONGODB_DB_NAME);
            await Promise.allSettled([
                db.collection(JSON_MIRROR_COLLECTION).createIndex({ updatedAt: -1 }),
                db.collection(STATUS_MEDIA_COLLECTION).createIndex({ expiresAt: 1 }, { expireAfterSeconds: 0, sparse: true })
            ]);
            console.log(`MongoDB connected: ${DEFAULT_MONGODB_DB_NAME}`);
            return { client, db };
        })().catch((error) => {
            mongoConnectionPromise = null;
            console.error('MongoDB Connection Error:', error?.message || error);
            return null;
        });
    }

    const connection = await mongoConnectionPromise;
    return connection?.db || null;
}

connectToDatabase().catch(() => {});


async function getMongoCollectionSafely(name) {
    if (!DATABASE_ENABLED) return null;
    const db = await connectToDatabase();
    if (!db) return null;
    const collectionName = String(name || '').trim();
    if (!collectionName) return null;
    return db.collection(collectionName);
}


function buildStatusMediaDocId(scope, ownerKey) {
    const seed = [String(scope || 'status-media').trim(), String(ownerKey || '').trim()].join('|');
    return crypto.createHash('sha1').update(seed).digest('hex');
}

async function deleteStatusMediaDocument(mediaId = '') {
    const normalizedMediaId = String(mediaId || '').trim();
    if (!normalizedMediaId) return false;
    const collection = await getMongoCollectionSafely(STATUS_MEDIA_COLLECTION);
    if (!collection) return false;
    try {
        await collection.deleteOne({ _id: normalizedMediaId });
        return true;
    } catch (error) {
        console.error(`⚠️ تعذر حذف وسائط الحالة ${normalizedMediaId} من MongoDB:`, error.message || error);
        return false;
    }
}

async function storeStatusMediaBuffer(scope, ownerKey, entry = {}, buffer, extra = {}) {
    if (!Buffer.isBuffer(buffer) || !buffer.length) return null;
    const collection = await getMongoCollectionSafely(STATUS_MEDIA_COLLECTION);
    if (!collection) return null;

    const normalizedScope = String(scope || 'status-media').trim() || 'status-media';
    const normalizedOwnerKey = String(ownerKey || '').trim() || crypto.randomUUID();
    const mediaId = buildStatusMediaDocId(normalizedScope, normalizedOwnerKey);
    const contentSha1 = crypto.createHash('sha1').update(buffer).digest('hex');
    const fileName = String(entry?.fileName || extra?.fileName || '').trim() || `${mediaId}.bin`;
    const createdAtValue = extra?.createdAt || entry?.createdAt || new Date().toISOString();
    const expiresAtValue = extra?.expiresAt || entry?.deletedExpiresAt || entry?.expiresAt || null;

    try {
        await collection.updateOne(
            { _id: mediaId },
            {
                $set: {
                    scope: normalizedScope,
                    ownerKey: normalizedOwnerKey,
                    archiveId: String(entry?.id || extra?.archiveId || '').trim(),
                    phone: normalizePhone(entry?.phone || extra?.phone || ''),
                    participant: normalizeWhatsAppJid(entry?.participant || extra?.participant || ''),
                    participantPhone: normalizePhone(entry?.participantPhone || extra?.participantPhone || ''),
                    messageId: String(entry?.messageId || extra?.messageId || '').trim(),
                    kind: String(entry?.kind || extra?.kind || '').trim(),
                    mimetype: String(entry?.mimetype || extra?.mimetype || 'application/octet-stream').trim() || 'application/octet-stream',
                    fileName,
                    byteLength: buffer.length,
                    contentSha1,
                    data: buffer,
                    createdAt: new Date(createdAtValue),
                    expiresAt: expiresAtValue ? new Date(expiresAtValue) : null,
                    updatedAt: new Date()
                }
            },
            { upsert: true }
        );
        return {
            mediaId,
            mediaStorage: 'mongo',
            mediaSize: buffer.length,
            mediaSha1: contentSha1,
            fileName
        };
    } catch (error) {
        console.error(`⚠️ تعذر حفظ وسائط الحالة ${normalizedOwnerKey} في MongoDB:`, error.message || error);
        return null;
    }
}

async function persistStatusMediaFromBuffer(scope, ownerKey, entry = {}, buffer, extra = {}) {
    const stored = await storeStatusMediaBuffer(scope, ownerKey, entry, buffer, extra);
    if (stored?.mediaId) {
        entry.mediaId = stored.mediaId;
        entry.mediaStorage = stored.mediaStorage;
        entry.mediaSize = stored.mediaSize;
        entry.mediaSha1 = stored.mediaSha1;
        entry.fileName = String(entry.fileName || stored.fileName || '').trim();
        entry.filePath = '';
        return true;
    }

    if (!ALLOW_STATUS_MEDIA_FILE_FALLBACK) {
        return false;
    }

    const fallbackFileName = String(entry.fileName || `${sanitizeFileFragment(ownerKey)}.bin`).trim();
    const fallbackPath = path.join(STATUS_MEDIA_DIR, fallbackFileName);
    fs.writeFileSync(fallbackPath, buffer);
    entry.fileName = fallbackFileName;
    entry.filePath = fallbackPath;
    entry.mediaId = '';
    entry.mediaStorage = 'filesystem';
    entry.mediaSize = buffer.length;
    entry.mediaSha1 = crypto.createHash('sha1').update(buffer).digest('hex');
    return true;
}

function normalizeMongoBinaryValue(value) {
    if (!value) return null;
    if (Buffer.isBuffer(value)) return value;
    if (Buffer.isBuffer(value?.buffer)) return value.buffer;
    if (typeof value?.value === 'function') {
        try {
            const raw = value.value(true);
            if (Buffer.isBuffer(raw)) return raw;
            if (raw) return Buffer.from(raw);
        } catch (_) {}
    }
    if (Array.isArray(value)) return Buffer.from(value);
    if (ArrayBuffer.isView(value)) return Buffer.from(value.buffer, value.byteOffset, value.byteLength);
    return null;
}

async function getStatusMediaBuffer(entry = {}) {
    const mediaId = String(entry?.mediaId || '').trim();
    if (mediaId) {
        const collection = await getMongoCollectionSafely(STATUS_MEDIA_COLLECTION);
        if (collection) {
            try {
                const doc = await collection.findOne({ _id: mediaId }, { projection: { data: 1 } });
                const buffer = normalizeMongoBinaryValue(doc?.data);
                if (buffer?.length) return buffer;
            } catch (error) {
                console.error(`⚠️ تعذر تحميل وسائط الحالة ${mediaId} من MongoDB:`, error.message || error);
            }
        }
    }

    if (entry?.filePath && fs.existsSync(entry.filePath)) {
        try {
            return fs.readFileSync(entry.filePath);
        } catch (_) {}
    }
    return null;
}

async function migrateStatusMediaEntriesToMongo() {
    const migrateEntries = async (db, collectionName) => {
        let changed = false;
        for (const [entryKey, entry] of Object.entries(db?.items || {})) {
            if (!entry || entry.kind === 'text' || entry.mediaId || !entry.filePath || !fs.existsSync(entry.filePath)) continue;
            try {
                const buffer = fs.readFileSync(entry.filePath);
                if (!buffer.length) continue;
                const persisted = await persistStatusMediaFromBuffer(collectionName, entry.id || entryKey, entry, buffer, {
                    archiveId: entry.id || '',
                    createdAt: entry.createdAt,
                    expiresAt: entry.deletedExpiresAt || entry.expiresAt || null,
                    phone: entry.phone,
                    participant: entry.participant,
                    participantPhone: entry.participantPhone,
                    messageId: entry.messageId,
                    kind: entry.kind,
                    mimetype: entry.mimetype,
                    fileName: entry.fileName
                });
                if (!persisted) continue;
                try { fs.rmSync(entry.filePath, { force: true }); } catch (_) {}
                entry.filePath = '';
                db.items[entryKey] = entry;
                changed = true;
            } catch (error) {
                console.error(`⚠️ تعذر ترحيل وسائط الحالة ${entry.id || entryKey} إلى MongoDB:`, error.message || error);
            }
        }
        return changed;
    };

    const backupsDb = getStatusBackupsDB();
    const archiveDb = getStatusArchiveDB();
    const backupsChanged = await migrateEntries(backupsDb, 'status_backup_media');
    const archiveChanged = await migrateEntries(archiveDb, 'status_archive_media');
    if (backupsChanged) saveStatusBackupsDB(backupsDb);
    if (archiveChanged) saveStatusArchiveDB(archiveDb);
}

const JSON_MIRROR_FILE_KEYS = new Map();
const JSON_MIRROR_CACHE = new Map();
const JSON_MIRROR_DEFAULTS = new Map();

function cloneJsonValue(value) {
    if (typeof value === 'undefined') return undefined;
    return JSON.parse(JSON.stringify(value));
}

function getJsonMirrorPathKey(filePath) {
    return path.resolve(filePath);
}

function registerJsonMirrorDefault(filePath, defaultValue) {
    const pathKey = getJsonMirrorPathKey(filePath);
    if (!JSON_MIRROR_DEFAULTS.has(pathKey)) {
        JSON_MIRROR_DEFAULTS.set(pathKey, cloneJsonValue(defaultValue));
    }
    if (!JSON_MIRROR_CACHE.has(pathKey)) {
        JSON_MIRROR_CACHE.set(pathKey, cloneJsonValue(defaultValue));
    }
    return cloneJsonValue(JSON_MIRROR_CACHE.get(pathKey));
}

function getJsonMirrorDefault(filePath, fallback = {}) {
    const pathKey = getJsonMirrorPathKey(filePath);
    if (JSON_MIRROR_DEFAULTS.has(pathKey)) {
        return cloneJsonValue(JSON_MIRROR_DEFAULTS.get(pathKey));
    }
    return cloneJsonValue(fallback);
}

function getJsonMirrorKey(filePath) {
    const normalized = getJsonMirrorPathKey(filePath);
    if (!JSON_MIRROR_FILE_KEYS.has(normalized)) {
        JSON_MIRROR_FILE_KEYS.set(normalized, path.basename(normalized));
    }
    return JSON_MIRROR_FILE_KEYS.get(normalized);
}

function readJsonFileFromDisk(filePath, fallback = {}) {
    try {
        if (!fs.existsSync(filePath)) return cloneJsonValue(fallback);
        const raw = fs.readFileSync(filePath, 'utf8');
        if (!raw.trim()) return cloneJsonValue(fallback);
        return JSON.parse(raw);
    } catch (_) {
        return cloneJsonValue(fallback);
    }
}

function writeJsonFileToDisk(filePath, data) {
    try {
        ensureDir(path.dirname(filePath));
        fs.writeFileSync(filePath, `${JSON.stringify(data, null, 2)}
`, 'utf8');
        return true;
    } catch (error) {
        console.error(`⚠️ تعذر كتابة الملف ${path.basename(filePath)} محلياً:`, error.message || error);
        return false;
    }
}

async function persistJsonMirror(filePath, data) {
    const pathKey = getJsonMirrorPathKey(filePath);
    const cloned = cloneJsonValue(data);
    JSON_MIRROR_CACHE.set(pathKey, cloned);
    const localSaved = writeJsonFileToDisk(filePath, cloned);

    const collection = await getMongoCollectionSafely(JSON_MIRROR_COLLECTION);
    if (collection) {
        try {
            await collection.updateOne(
                { _id: getJsonMirrorKey(filePath) },
                {
                    $set: {
                        pathKey,
                        fileName: path.basename(filePath),
                        data: cloned,
                        updatedAt: new Date().toISOString()
                    },
                    $setOnInsert: {
                        createdAt: new Date().toISOString()
                    }
                },
                { upsert: true }
            );
        } catch (error) {
            console.error(`JSON Mirror Mongo Save Error (${path.basename(filePath)}):`, error?.message || error);
        }
    }

    return localSaved;
}

async function restoreJsonMirror(filePath) {
    const pathKey = getJsonMirrorPathKey(filePath);
    const fallback = getJsonMirrorDefault(filePath, {});
    const collection = await getMongoCollectionSafely(JSON_MIRROR_COLLECTION);

    if (collection) {
        try {
            const remoteDoc = await collection.findOne({ _id: getJsonMirrorKey(filePath) });
            if (remoteDoc && typeof remoteDoc.data !== 'undefined') {
                const remoteData = cloneJsonValue(remoteDoc.data);
                JSON_MIRROR_CACHE.set(pathKey, remoteData);
                writeJsonFileToDisk(filePath, remoteData);
                return true;
            }
        } catch (error) {
            console.error(`JSON Mirror Mongo Restore Error (${path.basename(filePath)}):`, error?.message || error);
        }
    }

    const diskData = readJsonFileFromDisk(filePath, fallback);
    JSON_MIRROR_CACHE.set(pathKey, cloneJsonValue(diskData));
    if (!fs.existsSync(filePath)) {
        writeJsonFileToDisk(filePath, diskData);
    }

    if (collection) {
        try {
            await collection.updateOne(
                { _id: getJsonMirrorKey(filePath) },
                {
                    $setOnInsert: {
                        pathKey,
                        fileName: path.basename(filePath),
                        data: cloneJsonValue(diskData),
                        createdAt: new Date().toISOString(),
                        updatedAt: new Date().toISOString()
                    }
                },
                { upsert: true }
            );
        } catch (_) {}
    }

    return true;
}


function getSessionStorageDir(phone = '') {
    const raw = String(phone || '').trim();
    if (!raw) return path.join(SESSIONS_DIR, 'default');
    if (raw === '__web_qr__') return path.join(SESSIONS_DIR, '__web_qr__');
    const normalizedPhone = normalizePhone(raw);
    if (normalizedPhone) return getSessionPath(normalizedPhone);
    const safeName = raw.replace(/[^a-zA-Z0-9._-]+/g, '_') || 'default';
    return path.join(SESSIONS_DIR, safeName);
}

function getLocalSessionMetaFile(phone = '') {
    return path.join(getSessionStorageDir(phone), 'session-meta.json');
}

function readLocalSessionMeta(phone = '') {
    const raw = readJsonFileFromDisk(getLocalSessionMetaFile(phone), {});
    return {
        phone: normalizePhone(raw?.phone || phone) || String(raw?.phone || phone || '').trim(),
        ownerId: String(raw?.ownerId || '').trim(),
        registered: raw?.registered === true,
        lastConnectedAt: raw?.lastConnectedAt || null,
        updatedAt: raw?.updatedAt || null
    };
}

function writeLocalSessionMeta(phone = '', patch = {}) {
    const sessionKey = String(phone || '').trim() || 'default';
    const sessionDir = getSessionStorageDir(sessionKey);
    ensureDir(sessionDir);
    const current = readLocalSessionMeta(sessionKey);
    const normalizedPhone = normalizePhone(sessionKey);
    const next = {
        ...current,
        ...patch,
        phone: normalizedPhone || String(patch?.phone || current?.phone || sessionKey).trim(),
        ownerId: String(patch?.ownerId ?? current?.ownerId ?? '').trim(),
        registered: patch?.registered === true || current?.registered === true,
        lastConnectedAt: patch?.lastConnectedAt || current?.lastConnectedAt || null,
        updatedAt: new Date().toISOString()
    };
    writeJsonFileToDisk(getLocalSessionMetaFile(sessionKey), next);
    return next;
}

async function listLocalSessionEntries() {
    try {
        ensureDir(SESSIONS_DIR);
        const dirs = fs.readdirSync(SESSIONS_DIR, { withFileTypes: true })
            .filter((entry) => entry.isDirectory())
            .map((entry) => entry.name)
            .filter((name) => name !== '__web_qr__');

        const entries = [];
        for (const dirName of dirs) {
            const phone = normalizePhone(dirName);
            if (!phone) continue;
            const meta = readLocalSessionMeta(phone);
            const sessionDir = getSessionStorageDir(phone);
            const hasAuthFiles = fs.existsSync(path.join(sessionDir, 'creds.json')) || fs.existsSync(path.join(sessionDir, 'app-state-sync-key-1.json')) || fs.existsSync(getLocalSessionMetaFile(phone));
            if (!hasAuthFiles) continue;
            entries.push({
                sessionId: phone,
                phone,
                ownerId: String(meta?.ownerId || getPhoneOwner?.(phone) || '').trim(),
                registered: meta?.registered === true,
                lastConnectedAt: meta?.lastConnectedAt || meta?.updatedAt || null
            });
        }

        entries.sort((a, b) => (Date.parse(b?.lastConnectedAt || 0) || 0) - (Date.parse(a?.lastConnectedAt || 0) || 0));
        return entries;
    } catch (error) {
        console.error('Local Session Scan Error:', error.message || error);
        return [];
    }
}

async function persistMongoSessionStateDirect(phone, creds, keysData, metadata = {}) {
    const normalizedPhone = normalizePhone(phone);
    if (!normalizedPhone) return false;
    const registered = metadata.registered === true || creds?.registered === true;
    const lastConnectedAt = metadata.lastConnectedAt || null;
    writeLocalSessionMeta(normalizedPhone, {
        ownerId: metadata.ownerId || getPhoneOwner?.(normalizedPhone) || '',
        registered,
        lastConnectedAt
    });
    await syncSessionToRemoteStore(normalizedPhone, {
        ownerId: metadata.ownerId || getPhoneOwner?.(normalizedPhone) || '',
        registered,
        lastConnectedAt
    });
    return true;
}

async function touchMongoSessionState(phone, metadata = {}) {
    const normalizedPhone = typeof normalizePhone === 'function' ? normalizePhone(phone) : String(phone || '').replace(/\D/g, '');
    if (!normalizedPhone) return false;
    const payload = {
        ownerId: metadata.ownerId || getPhoneOwner?.(normalizedPhone) || '',
        registered: metadata.registered === true,
        lastConnectedAt: metadata.lastConnectedAt || null
    };
    writeLocalSessionMeta(normalizedPhone, payload);

    const store = getSessionStoreDB();
    const current = toLocalSessionIndexRecord(normalizedPhone, store.sessions?.[normalizedPhone] || {}) || toLocalSessionIndexRecord(normalizedPhone, {});
    store.sessions[normalizedPhone] = {
        ...current,
        phone: normalizedPhone,
        sessionId: normalizedPhone,
        ownerId: payload.ownerId,
        registered: payload.registered || current?.registered === true,
        lastConnectedAt: payload.lastConnectedAt || current?.lastConnectedAt || null,
        updatedAt: new Date().toISOString(),
        fileCount: Number(current?.fileCount || 0)
    };
    saveSessionStoreDB(store);

    if (isRemoteSessionStoreEnabled()) {
        try {
            await touchRemoteSession(normalizedPhone, store.sessions[normalizedPhone]);
        } catch (error) {
            console.error(`Remote Session Touch Error (${normalizedPhone}):`, error.message || error);
        }
    }
    return true;
}

async function deleteMongoSessionState(phone) {
    const rawPhone = String(phone || '').trim();
    const normalizedPhone = normalizePhone(rawPhone);
    const sessionKey = normalizedPhone || rawPhone || 'default';
    const sessionDir = getSessionStorageDir(sessionKey);
    try {
        fs.rmSync(sessionDir, { recursive: true, force: true });
    } catch (error) {
        console.error(`⚠️ تعذر حذف الجلسة المحلية ${sessionKey}:`, error.message || error);
    }

    deleteSessionStoreRecordLocal(sessionKey);

    if (normalizedPhone && isRemoteSessionStoreEnabled()) {
        try {
            await deleteRemoteSession(normalizedPhone);
        } catch (error) {
            console.error(`⚠️ تعذر حذف الجلسة البعيدة ${normalizedPhone}:`, error.message || error);
        }
    }

    return true;
}

async function updateMongoSessionMetadataOnly(phone, metadata = {}) {
    const normalizedPhone = typeof normalizePhone === 'function' ? normalizePhone(phone) : String(phone || '').replace(/\D/g, '');
    if (!normalizedPhone) return false;
    const payload = {
        ownerId: metadata.ownerId || getPhoneOwner?.(normalizedPhone) || '',
        registered: metadata.registered === true,
        ...(metadata.lastConnectedAt ? { lastConnectedAt: metadata.lastConnectedAt } : {})
    };
    writeLocalSessionMeta(normalizedPhone, payload);
    await touchMongoSessionState(normalizedPhone, payload);
    return true;
}

function extractSessionIdFromMongoDocument(doc = {}) {
    const queue = [doc?.sessionId, doc?.phone, doc?.id, doc?._id, doc?.jid, doc?.number];
    for (const candidate of queue) {
        if (candidate == null) continue;
        const normalized = normalizePhone(candidate);
        if (normalized) return normalized;
        if (typeof candidate === 'string') {
            const match = candidate.match(/(\d{6,20})/);
            if (match && match[1]) {
                const extracted = normalizePhone(match[1]);
                if (extracted) return extracted;
            }
        }
    }
    return '';
}

async function getStoredMongoSessionEntries() {
    if (isRemoteSessionStoreEnabled()) {
        try {
            const sessions = await listRemoteSessions();
            if (Array.isArray(sessions) && sessions.length) {
                const normalized = sessions
                    .map((entry) => normalizeSessionStoreRecord(entry?.phone || entry?.sessionId || '', entry || {}))
                    .filter(Boolean)
                    .map((entry) => ({
                        sessionId: entry.phone,
                        phone: entry.phone,
                        ownerId: String(entry.ownerId || '').trim(),
                        registered: entry.registered === true,
                        lastConnectedAt: entry.lastConnectedAt || entry.updatedAt || null
                    }));

                if (normalized.length) {
                    const store = getSessionStoreDB();
                    for (const entry of normalized) {
                        const current = toLocalSessionIndexRecord(entry.phone, store.sessions?.[entry.phone] || {}) || toLocalSessionIndexRecord(entry.phone, {});
                        store.sessions[entry.phone] = {
                            ...current,
                            phone: entry.phone,
                            sessionId: entry.phone,
                            ownerId: entry.ownerId,
                            registered: entry.registered,
                            lastConnectedAt: entry.lastConnectedAt || current?.lastConnectedAt || null,
                            updatedAt: new Date().toISOString(),
                            fileCount: Number(current?.fileCount || entry?.fileCount || 0)
                        };
                    }
                    saveSessionStoreDB(store);
                    return normalized;
                }
            }
        } catch (error) {
            console.error('Remote Session List Warning:', error.message || error);
        }
    }

    const storeEntries = Object.values(getSessionStoreDB().sessions || {})
        .map((entry) => normalizeSessionStoreRecord(entry?.phone || entry?.sessionId || '', entry || {}))
        .filter(Boolean)
        .map((entry) => ({
            sessionId: entry.phone,
            phone: entry.phone,
            ownerId: entry.ownerId,
            registered: entry.registered === true,
            lastConnectedAt: entry.lastConnectedAt || entry.updatedAt || null
        }));

    if (storeEntries.length) {
        return storeEntries;
    }

    return listLocalSessionEntries();
}

async function getMongoAuthState(phone) {
    const sessionKey = String(phone || 'default').trim() || 'default';
    const normalizedPhone = normalizePhone(sessionKey);
    const sessionDir = getSessionStorageDir(sessionKey);
    ensureDir(sessionDir);

    if (normalizedPhone) {
        await ensureSessionStateReady(normalizedPhone);
    }

    if (normalizedPhone && !sessionHasLocalAuthFiles(normalizedPhone)) {
        await restoreSessionFromRemoteStore(normalizedPhone);
    }

    const helperAuth = await useMultiFileAuthState(sessionDir);
    const state = helperAuth.state;

    if (!state?.keys?.__remoteSyncWrapped && typeof state?.keys?.set === 'function') {
        const originalSet = state.keys.set.bind(state.keys);
        state.keys.set = async (data, ...args) => {
            const result = await originalSet(data, ...args);
            const hasMutations = data && typeof data === 'object' && Object.values(data).some((bucket) => bucket && typeof bucket === 'object' && Object.keys(bucket).length > 0);
            if (hasMutations && normalizedPhone) {
                scheduleSessionSnapshotSync(normalizedPhone, {
                    ownerId: getPhoneOwner?.(normalizedPhone) || '',
                    registered: state?.creds?.registered === true,
                    lastConnectedAt: readLocalSessionMeta(normalizedPhone)?.lastConnectedAt || null
                });
            }
            return result;
        };
        Object.defineProperty(state.keys, '__remoteSyncWrapped', {
            value: true,
            enumerable: false,
            configurable: true,
            writable: false
        });
    }

    const saveCreds = async (metadata = {}) => {
        const registered = metadata.registered === true || state?.creds?.registered === true;
        const payload = {
            ownerId: metadata.ownerId || getPhoneOwner?.(normalizedPhone) || '',
            registered,
            lastConnectedAt: metadata.lastConnectedAt || null
        };

        await helperAuth.saveCreds();
        writeLocalSessionMeta(sessionKey, {
            phone: normalizedPhone || sessionKey,
            ownerId: payload.ownerId,
            registered,
            lastConnectedAt: payload.lastConnectedAt
        });

        await flushSessionSnapshotSync(normalizedPhone || sessionKey, payload);
    };

    return { state, saveCreds };
}


async function restorePersistentFilesFromMongo() {
    const files = [USERS_FILE, SETTINGS_FILE, PHONE_SETTINGS_FILE, BOT_ANALYTICS_FILE, STATUS_BACKUPS_FILE, STATUS_ARCHIVE_FILE, PROFILE_SCHEDULE_FILE, CONTACTS_ARCHIVE_FILE, DELETED_MESSAGES_ARCHIVE_FILE];
    for (const filePath of files) {
        await restoreJsonMirror(filePath);
    }
}

// =========================
// أدوات الملفات والبيانات
// =========================
function ensureDir(dirPath) {
    if (!fs.existsSync(dirPath)) {
        fs.mkdirSync(dirPath, { recursive: true });
    }
}

function ensureFile(filePath, defaultValue) {
    registerJsonMirrorDefault(filePath, defaultValue);
    const pathKey = getJsonMirrorPathKey(filePath);
    if (!fs.existsSync(filePath)) {
        writeJsonFileToDisk(filePath, cloneJsonValue(defaultValue));
        JSON_MIRROR_CACHE.set(pathKey, cloneJsonValue(defaultValue));
        return cloneJsonValue(defaultValue);
    }
    const loaded = readJsonFileFromDisk(filePath, defaultValue);
    JSON_MIRROR_CACHE.set(pathKey, cloneJsonValue(loaded));
    return cloneJsonValue(loaded);
}

function readJSON(filePath, fallback = {}) {
    const pathKey = getJsonMirrorPathKey(filePath);
    if (JSON_MIRROR_CACHE.has(pathKey)) {
        return cloneJsonValue(JSON_MIRROR_CACHE.get(pathKey));
    }
    if (fs.existsSync(filePath)) {
        const loaded = readJsonFileFromDisk(filePath, fallback);
        JSON_MIRROR_CACHE.set(pathKey, cloneJsonValue(loaded));
        return cloneJsonValue(loaded);
    }
    return ensureFile(filePath, fallback);
}

function writeJSON(filePath, data) {
    const pathKey = getJsonMirrorPathKey(filePath);
    const cloned = cloneJsonValue(data);
    JSON_MIRROR_CACHE.set(pathKey, cloned);
    writeJsonFileToDisk(filePath, cloned);
}

function getDefaultSessionStoreDB() {
    return { sessions: {} };
}

function getSessionStoreDB() {
    const db = readJSON(SESSION_STORE_FILE, getDefaultSessionStoreDB());
    db.sessions = db.sessions || {};
    return db;
}

function saveSessionStoreDB(db) {
    db.sessions = db.sessions || {};
    writeJSON(SESSION_STORE_FILE, db);
    return db;
}

function normalizeSessionStoreRecord(phone, payload = {}) {
    const normalizedPhone = normalizePhone(phone || payload.phone || payload.sessionId || '');
    if (!normalizedPhone) return null;

    const files = {};
    for (const [fileName, rawContent] of Object.entries(payload.files || {})) {
        const safeName = path.basename(String(fileName || '').trim());
        if (!safeName || !safeName.endsWith('.json')) continue;
        if (typeof rawContent !== 'string') continue;
        files[safeName] = rawContent;
    }

    return {
        phone: normalizedPhone,
        sessionId: normalizedPhone,
        ownerId: String(payload.ownerId || '').trim(),
        registered: payload.registered === true,
        lastConnectedAt: payload.lastConnectedAt || null,
        updatedAt: payload.updatedAt || new Date().toISOString(),
        files,
        fileCount: Object.keys(files).length
    };
}

function toLocalSessionIndexRecord(phone, payload = {}) {
    const normalized = normalizeSessionStoreRecord(phone, payload);
    if (!normalized) return null;
    return {
        phone: normalized.phone,
        sessionId: normalized.sessionId,
        ownerId: normalized.ownerId,
        registered: normalized.registered === true,
        lastConnectedAt: normalized.lastConnectedAt || null,
        updatedAt: normalized.updatedAt || new Date().toISOString(),
        fileCount: Number(payload.fileCount || normalized.fileCount || Object.keys(payload.files || {}).length || 0)
    };
}

function listLocalSessionJsonFiles(phone = '') {
    const sessionDir = getSessionStorageDir(phone);
    if (!fs.existsSync(sessionDir)) return [];
    try {
        return fs.readdirSync(sessionDir)
            .filter((fileName) => fileName && fileName.endsWith('.json'))
            .sort();
    } catch (_) {
        return [];
    }
}

function sessionHasLocalAuthFiles(phone = '') {
    return listLocalSessionJsonFiles(phone).some((fileName) => fileName === 'creds.json' || fileName.startsWith('app-state-sync-') || fileName.startsWith('pre-key-') || fileName.startsWith('sender-key-') || fileName.startsWith('session-'));
}

const LOCAL_SESSION_FILE_LIMITS = Object.freeze({
    prekey: Math.max(20, Number(process.env.LOCAL_SESSION_MAX_PRE_KEYS || 60)),
    session: Math.max(20, Number(process.env.LOCAL_SESSION_MAX_SIGNAL_SESSIONS || 80)),
    sender: Math.max(20, Number(process.env.LOCAL_SESSION_MAX_SENDER_KEYS || 80))
});

function classifySessionJsonFile(fileName = '') {
    const normalized = String(fileName || '').trim();
    if (!normalized.endsWith('.json')) return 'other';
    if (normalized === 'creds.json') return 'creds';
    if (normalized === 'session-meta.json') return 'meta';
    if (normalized.startsWith('app-state-sync-')) return 'app-state';
    if (normalized.startsWith('pre-key-')) return 'prekey';
    if (normalized.startsWith('sender-key-')) return 'sender';
    if (normalized.startsWith('session-')) return 'session';
    return 'other';
}

function rankSessionJsonFilesForRetention(fileNames = []) {
    return [...fileNames].sort((left, right) => {
        const l = String(left || '');
        const r = String(right || '');
        const lMatch = l.match(/(\d+)/g);
        const rMatch = r.match(/(\d+)/g);
        const lScore = lMatch ? Number(lMatch[lMatch.length - 1]) || 0 : 0;
        const rScore = rMatch ? Number(rMatch[rMatch.length - 1]) || 0 : 0;
        if (lScore !== rScore) return rScore - lScore;
        return r.localeCompare(l);
    });
}

function pruneSessionDirectoryFiles(phone = '') {
    const normalizedPhone = normalizePhone(phone);
    if (!normalizedPhone) return false;
    const sessionDir = getSessionStorageDir(normalizedPhone);
    if (!fs.existsSync(sessionDir)) return false;

    const keepAlways = new Set(['creds.json', 'session-meta.json']);
    const grouped = { prekey: [], session: [], sender: [] };
    let changed = false;

    for (const fileName of listLocalSessionJsonFiles(normalizedPhone)) {
        const category = classifySessionJsonFile(fileName);
        if (category === 'app-state' || keepAlways.has(fileName)) continue;
        if (grouped[category]) {
            grouped[category].push(fileName);
        }
    }

    const limits = {
        prekey: LOCAL_SESSION_FILE_LIMITS.prekey,
        session: LOCAL_SESSION_FILE_LIMITS.session,
        sender: LOCAL_SESSION_FILE_LIMITS.sender
    };

    for (const [category, files] of Object.entries(grouped)) {
        const ranked = rankSessionJsonFilesForRetention(files);
        const remove = ranked.slice(limits[category]);
        for (const fileName of remove) {
            try {
                fs.unlinkSync(path.join(sessionDir, fileName));
                changed = true;
            } catch (_) {}
        }
    }

    return changed;
}

function collectSessionDirectorySnapshot(phone = '', metadata = {}) {
    const normalizedPhone = normalizePhone(phone);
    if (!normalizedPhone) return null;

    const sessionDir = getSessionStorageDir(normalizedPhone);
    ensureDir(sessionDir);
    pruneSessionDirectoryFiles(normalizedPhone);
    const files = {};

    for (const fileName of listLocalSessionJsonFiles(normalizedPhone)) {
        const filePath = path.join(sessionDir, fileName);
        try {
            files[fileName] = fs.readFileSync(filePath, 'utf8');
        } catch (error) {
            console.error(`Session Snapshot Read Error (${normalizedPhone}/${fileName}):`, error.message || error);
        }
    }

    return normalizeSessionStoreRecord(normalizedPhone, {
        ownerId: metadata.ownerId || getPhoneOwner?.(normalizedPhone) || '',
        registered: metadata.registered === true,
        lastConnectedAt: metadata.lastConnectedAt || null,
        files
    });
}

function writeSessionDirectorySnapshot(phone = '', payload = {}) {
    const record = normalizeSessionStoreRecord(phone, payload);
    if (!record) return false;

    const sessionDir = getSessionStorageDir(record.phone);
    ensureDir(sessionDir);

    const allowedFiles = new Set(Object.keys(record.files || {}));
    for (const existingFile of listLocalSessionJsonFiles(record.phone)) {
        if (!allowedFiles.has(existingFile)) {
            try {
                fs.unlinkSync(path.join(sessionDir, existingFile));
            } catch (_) {}
        }
    }

    for (const [fileName, content] of Object.entries(record.files || {})) {
        fs.writeFileSync(path.join(sessionDir, fileName), String(content || ''), 'utf8');
    }

    writeLocalSessionMeta(record.phone, {
        ownerId: record.ownerId || getPhoneOwner?.(record.phone) || '',
        registered: record.registered === true,
        lastConnectedAt: record.lastConnectedAt || null
    });

    const store = getSessionStoreDB();
    store.sessions[record.phone] = toLocalSessionIndexRecord(record.phone, record);
    saveSessionStoreDB(store);
    return true;
}

function deleteSessionStoreRecordLocal(phone = '') {
    const normalizedPhone = normalizePhone(phone);
    if (!normalizedPhone) return false;
    const store = getSessionStoreDB();
    if (!store.sessions[normalizedPhone]) return false;
    delete store.sessions[normalizedPhone];
    saveSessionStoreDB(store);
    return true;
}

async function restoreSessionFromRemoteStore(phone = '') {
    const normalizedPhone = normalizePhone(phone);
    if (!normalizedPhone) return false;

    if (isRemoteSessionStoreEnabled()) {
        try {
            const remoteRecord = await fetchRemoteSession(normalizedPhone);
            const normalizedRecord = normalizeSessionStoreRecord(normalizedPhone, remoteRecord || {});
            if (normalizedRecord && Object.keys(normalizedRecord.files || {}).length) {
                writeSessionDirectorySnapshot(normalizedPhone, normalizedRecord);
                return true;
            }
        } catch (error) {
            console.error(`Remote Session Restore Error (${normalizedPhone}):`, error.message || error);
        }
    }

    const store = getSessionStoreDB();
    const localRecord = normalizeSessionStoreRecord(normalizedPhone, store.sessions?.[normalizedPhone] || {});
    if (localRecord && Object.keys(localRecord.files || {}).length) {
        writeSessionDirectorySnapshot(normalizedPhone, localRecord);
        return true;
    }

    return false;
}

async function syncSessionToRemoteStore(phone = '', metadata = {}) {
    const normalizedPhone = normalizePhone(phone);
    if (!normalizedPhone) return false;

    const snapshot = collectSessionDirectorySnapshot(normalizedPhone, metadata);
    if (!snapshot) return false;

    snapshot.ownerId = String(metadata.ownerId || snapshot.ownerId || getPhoneOwner?.(normalizedPhone) || '').trim();
    snapshot.registered = metadata.registered === true || snapshot.registered === true;
    snapshot.lastConnectedAt = metadata.lastConnectedAt || snapshot.lastConnectedAt || null;
    snapshot.updatedAt = new Date().toISOString();

    const store = getSessionStoreDB();
    store.sessions[normalizedPhone] = toLocalSessionIndexRecord(normalizedPhone, snapshot);
    saveSessionStoreDB(store);

    if (!isRemoteSessionStoreEnabled()) return true;

    try {
        await upsertRemoteSession(normalizedPhone, snapshot);
        return true;
    } catch (error) {
        console.error(`Remote Session Sync Error (${normalizedPhone}):`, error.message || error);
        return false;
    }
}

function mergeSessionSyncMetadata(phone = '', ...sources) {
    const normalizedPhone = normalizePhone(phone);
    const localMeta = normalizedPhone ? readLocalSessionMeta(normalizedPhone) : {};
    const merged = {
        ownerId: '',
        registered: false,
        lastConnectedAt: null
    };

    for (const source of [localMeta, ...sources]) {
        if (!source || typeof source !== 'object') continue;
        if (String(source.ownerId || '').trim()) {
            merged.ownerId = String(source.ownerId || '').trim();
        }
        if (source.registered === true) {
            merged.registered = true;
        }
        if (source.lastConnectedAt) {
            merged.lastConnectedAt = source.lastConnectedAt;
        }
    }

    if (!merged.ownerId && normalizedPhone) {
        merged.ownerId = String(getPhoneOwner?.(normalizedPhone) || '').trim();
    }

    return merged;
}

async function flushSessionSnapshotSync(phone = '', metadata = {}) {
    const normalizedPhone = normalizePhone(phone);
    if (!normalizedPhone) return false;

    const timer = sessionSnapshotSyncTimers.get(normalizedPhone);
    if (timer) {
        clearTimeout(timer);
        sessionSnapshotSyncTimers.delete(normalizedPhone);
    }

    const mergedMetadata = mergeSessionSyncMetadata(
        normalizedPhone,
        sessionSnapshotSyncMetadata.get(normalizedPhone) || {},
        metadata || {}
    );
    sessionSnapshotSyncMetadata.set(normalizedPhone, mergedMetadata);

    const previous = sessionSnapshotSyncPromises.get(normalizedPhone) || Promise.resolve(false);
    const current = previous
        .catch(() => false)
        .then(async () => syncSessionToRemoteStore(normalizedPhone, mergeSessionSyncMetadata(normalizedPhone, sessionSnapshotSyncMetadata.get(normalizedPhone) || {})));

    sessionSnapshotSyncPromises.set(normalizedPhone, current);

    try {
        return await current;
    } finally {
        if (sessionSnapshotSyncPromises.get(normalizedPhone) === current) {
            sessionSnapshotSyncPromises.delete(normalizedPhone);
        }
    }
}

function scheduleSessionSnapshotSync(phone = '', metadata = {}, delayMs = SESSION_REMOTE_SYNC_DEBOUNCE_MS) {
    const normalizedPhone = normalizePhone(phone);
    if (!normalizedPhone) return Promise.resolve(false);

    const mergedMetadata = mergeSessionSyncMetadata(
        normalizedPhone,
        sessionSnapshotSyncMetadata.get(normalizedPhone) || {},
        metadata || {}
    );
    sessionSnapshotSyncMetadata.set(normalizedPhone, mergedMetadata);

    const existingTimer = sessionSnapshotSyncTimers.get(normalizedPhone);
    if (existingTimer) {
        clearTimeout(existingTimer);
    }

    return new Promise((resolve) => {
        const timer = setTimeout(async () => {
            sessionSnapshotSyncTimers.delete(normalizedPhone);
            try {
                resolve(await flushSessionSnapshotSync(normalizedPhone));
            } catch (error) {
                console.error(`Session Debounced Sync Error (${normalizedPhone}):`, error.message || error);
                resolve(false);
            }
        }, Math.max(0, Number(delayMs) || 0));

        if (typeof timer.unref === 'function') {
            timer.unref();
        }

        sessionSnapshotSyncTimers.set(normalizedPhone, timer);
    });
}

async function flushAllSessionSnapshotSyncs() {
    const phones = new Set([
        ...sessionSnapshotSyncMetadata.keys(),
        ...sessionSnapshotSyncTimers.keys(),
        ...waClients.keys()
    ]);

    if (!phones.size) return [];

    return Promise.allSettled(
        Array.from(phones).map((phone) => flushSessionSnapshotSync(phone))
    );
}

function getSessionDirectoryHealth(phone = '') {
    const normalizedPhone = normalizePhone(phone);
    const meta = readLocalSessionMeta(normalizedPhone);
    const files = listLocalSessionJsonFiles(normalizedPhone);
    const invalidFiles = [];
    let credsValid = false;
    let hasCredsFile = false;
    let hasSignalMaterial = false;

    for (const fileName of files) {
        const category = classifySessionJsonFile(fileName);
        if (category === 'meta' || category === 'other') continue;
        const filePath = path.join(getSessionStorageDir(normalizedPhone), fileName);

        if (fileName === 'creds.json') {
            hasCredsFile = true;
        }
        if (['app-state', 'prekey', 'sender', 'session'].includes(category)) {
            hasSignalMaterial = true;
        }

        try {
            JSON.parse(fs.readFileSync(filePath, 'utf8'));
            if (fileName === 'creds.json') {
                credsValid = true;
            }
        } catch (_) {
            invalidFiles.push(fileName);
        }
    }

    const isRegistered = meta?.registered === true;
    const hasUsableAuth = credsValid && invalidFiles.length === 0 && (hasSignalMaterial || !isRegistered);

    return {
        normalizedPhone,
        meta,
        files,
        invalidFiles,
        hasCredsFile,
        credsValid,
        hasSignalMaterial,
        hasUsableAuth
    };
}

async function ensureSessionStateReady(phone = '', options = {}) {
    const normalizedPhone = normalizePhone(phone);
    if (!normalizedPhone) {
        return { ready: false, restored: false, health: null };
    }

    let health = getSessionDirectoryHealth(normalizedPhone);
    let restored = false;
    const shouldRestoreFromRemote = options.forceRemote === true || !health.hasUsableAuth || health.invalidFiles.length > 0;

    if (shouldRestoreFromRemote && isRemoteSessionStoreEnabled()) {
        try {
            const remoteRecord = await fetchRemoteSession(normalizedPhone);
            const remoteFilesCount = Object.keys(remoteRecord?.files || {}).length;
            if (remoteFilesCount > 0) {
                writeSessionDirectorySnapshot(normalizedPhone, remoteRecord);
                restored = true;
                health = getSessionDirectoryHealth(normalizedPhone);
            }
        } catch (error) {
            console.error(`Remote Session Prepare Error (${normalizedPhone}):`, error.message || error);
        }
    }

    return {
        ready: health.hasUsableAuth,
        restored,
        health
    };
}

function removeDirRecursive(dirPath) {
    if (!dirPath || !fs.existsSync(dirPath)) return;
    fs.rmSync(dirPath, { recursive: true, force: true });
}

function listPhoneProfileDirectories() {
    try {
        ensureDir(PHONE_PROFILES_DIR);
        return fs.readdirSync(PHONE_PROFILES_DIR, { withFileTypes: true })
            .filter((entry) => entry.isDirectory())
            .map((entry) => entry.name);
    } catch (error) {
        console.error('Phone Profile Directory Read Error:', error.message);
        return [];
    }
}

function getPhoneProfileDir(phone) {
    const normalizedPhone = normalizePhone(phone);
    return normalizedPhone ? path.join(PHONE_PROFILES_DIR, normalizedPhone) : PHONE_PROFILES_DIR;
}

function getPhoneProfileSettingsFile(phone) {
    return path.join(getPhoneProfileDir(phone), 'settings.json');
}

function getPhoneProfileCredentialsFile(phone) {
    return path.join(getPhoneProfileDir(phone), 'credentials.json');
}

function getPhoneProfileMetaFile(phone) {
    return path.join(getPhoneProfileDir(phone), 'meta.json');
}

function getSessionPhoneProfileDir(phone) {
    return getSessionStorageDir(phone);
}

function getSessionPhoneProfileSettingsFile(phone) {
    return path.join(getSessionPhoneProfileDir(phone), 'phone-settings-profile.json');
}

function getSessionPhoneProfileCredentialsFile(phone) {
    return path.join(getSessionPhoneProfileDir(phone), 'phone-settings-credentials.json');
}

function getSessionPhoneProfileMetaFile(phone) {
    return path.join(getSessionPhoneProfileDir(phone), 'phone-settings-meta.json');
}

function mergePhoneProfileRecords(...records) {
    const merged = {
        activeAppId: 'default',
        apps: {},
        credentials: {}
    };

    for (const record of records) {
        if (!record || typeof record !== 'object') continue;

        const candidateActiveAppId = normalizeAppId(record.activeAppId || merged.activeAppId || 'default');
        merged.activeAppId = candidateActiveAppId || merged.activeAppId || 'default';

        const apps = record.apps && typeof record.apps === 'object' ? record.apps : {};
        for (const [rawAppId, settings] of Object.entries(apps)) {
            const appId = normalizeAppId(rawAppId);
            merged.apps[appId] = {
                ...cloneDefaultPhoneSettings(),
                ...(merged.apps[appId] || {}),
                ...(settings && typeof settings === 'object' ? cloneJsonValue(settings) : {})
            };
        }

        const credentials = record.credentials && typeof record.credentials === 'object' ? record.credentials : {};
        for (const [rawAppId, credential] of Object.entries(credentials)) {
            const appId = normalizeAppId(rawAppId);
            const currentCredential = merged.credentials[appId] || {};
            const nextCredential = credential && typeof credential === 'object' ? cloneJsonValue(credential) : {};
            merged.credentials[appId] = {
                ...currentCredential,
                ...nextCredential,
                password: String(nextCredential.password || currentCredential.password || '').trim() || generateSettingsPassword(),
                createdAt: nextCredential.createdAt || currentCredential.createdAt || new Date().toISOString(),
                updatedAt: nextCredential.updatedAt || currentCredential.updatedAt || new Date().toISOString()
            };
        }
    }

    const appIds = Array.from(new Set([
        normalizeAppId(merged.activeAppId || 'default'),
        ...Object.keys(merged.apps || {}).map((item) => normalizeAppId(item)),
        ...Object.keys(merged.credentials || {}).map((item) => normalizeAppId(item))
    ].filter(Boolean)));

    if (!appIds.length) {
        appIds.push('default');
    }

    if (!merged.apps[merged.activeAppId]) {
        const seedAppId = appIds.find((appId) => merged.apps[appId]) || 'default';
        merged.apps[merged.activeAppId] = {
            ...cloneDefaultPhoneSettings(),
            ...(merged.apps[seedAppId] || {})
        };
    }

    for (const appId of appIds) {
        merged.apps[appId] = {
            ...cloneDefaultPhoneSettings(),
            ...(merged.apps[appId] || {})
        };

        const currentCredential = merged.credentials[appId] || {};
        merged.credentials[appId] = {
            ...currentCredential,
            password: String(currentCredential.password || '').trim() || generateSettingsPassword(),
            createdAt: currentCredential.createdAt || new Date().toISOString(),
            updatedAt: currentCredential.updatedAt || new Date().toISOString()
        };
    }

    return merged;
}

function readPhoneProfileFromDirectoryFiles(phone, files = {}) {
    const normalizedPhone = normalizePhone(phone || files.phone || '');
    if (!normalizedPhone) return null;

    const settingsData = files.settingsFile ? readJsonFileFromDisk(files.settingsFile, null) : null;
    const credentialsData = files.credentialsFile ? readJsonFileFromDisk(files.credentialsFile, null) : null;
    const metaData = files.metaFile ? readJsonFileFromDisk(files.metaFile, null) : null;

    if (!settingsData && !credentialsData && !metaData) {
        return null;
    }

    return mergePhoneProfileRecords(
        settingsData && typeof settingsData === 'object'
            ? { activeAppId: settingsData.activeAppId, apps: settingsData.apps || settingsData.settings || {} }
            : null,
        credentialsData && typeof credentialsData === 'object'
            ? { credentials: credentialsData.credentials || credentialsData }
            : null,
        metaData && typeof metaData === 'object'
            ? { activeAppId: metaData.activeAppId || settingsData?.activeAppId || 'default' }
            : null
    );
}

function syncPhoneProfileToDirectory(phone, profile = {}) {
    const normalizedPhone = normalizePhone(phone);
    if (!normalizedPhone) return profile;

    const mergedProfile = mergePhoneProfileRecords(profile);
    const sessionDir = getSessionPhoneProfileDir(normalizedPhone);
    ensureDir(sessionDir);

    writeJsonFileToDisk(getSessionPhoneProfileSettingsFile(normalizedPhone), {
        phone: normalizedPhone,
        activeAppId: mergedProfile.activeAppId,
        apps: mergedProfile.apps,
        updatedAt: new Date().toISOString()
    });

    writeJsonFileToDisk(getSessionPhoneProfileCredentialsFile(normalizedPhone), {
        phone: normalizedPhone,
        credentials: mergedProfile.credentials,
        updatedAt: new Date().toISOString()
    });

    writeJsonFileToDisk(getSessionPhoneProfileMetaFile(normalizedPhone), {
        phone: normalizedPhone,
        activeAppId: mergedProfile.activeAppId,
        appIds: Object.keys(mergedProfile.apps || {}),
        updatedAt: new Date().toISOString()
    });

    return mergedProfile;
}

function hydratePhoneSettingsFromDirectories(db) {
    db.profiles = db.profiles || {};

    const knownPhones = new Set(
        Object.keys(db.profiles || {})
            .map((phone) => normalizePhone(phone))
            .filter(Boolean)
    );

    try {
        ensureDir(SESSIONS_DIR);
        const sessionDirs = fs.readdirSync(SESSIONS_DIR, { withFileTypes: true })
            .filter((entry) => entry.isDirectory())
            .map((entry) => normalizePhone(entry.name))
            .filter(Boolean);
        for (const phone of sessionDirs) {
            knownPhones.add(phone);
        }
    } catch (_) {}

    for (const phone of listPhoneProfileDirectories().map((item) => normalizePhone(item)).filter(Boolean)) {
        knownPhones.add(phone);
    }

    let changed = false;
    for (const phone of knownPhones) {
        const mergedProfile = mergePhoneProfileRecords(
            db.profiles[phone] || null,
            readPhoneProfileFromDirectoryFiles(phone, {
                phone,
                settingsFile: getPhoneProfileSettingsFile(phone),
                credentialsFile: getPhoneProfileCredentialsFile(phone),
                metaFile: getPhoneProfileMetaFile(phone)
            }),
            readPhoneProfileFromDirectoryFiles(phone, {
                phone,
                settingsFile: getSessionPhoneProfileSettingsFile(phone),
                credentialsFile: getSessionPhoneProfileCredentialsFile(phone),
                metaFile: getSessionPhoneProfileMetaFile(phone)
            })
        );

        if (!Object.keys(mergedProfile.apps || {}).length) continue;

        const previousSerialized = JSON.stringify(db.profiles[phone] || {});
        const nextSerialized = JSON.stringify(mergedProfile);
        if (previousSerialized !== nextSerialized) {
            db.profiles[phone] = mergedProfile;
            changed = true;
        }

        if (!fs.existsSync(getSessionPhoneProfileSettingsFile(phone)) || !fs.existsSync(getSessionPhoneProfileCredentialsFile(phone))) {
            syncPhoneProfileToDirectory(phone, mergedProfile);
        }
    }

    if (changed) {
        _phoneSettingsDBCache = db;
        _phoneSettingsDBCacheAt = Date.now();
    }

    return db;
}

function deletePhoneProfileDirectory(phone) {
    const normalizedPhone = normalizePhone(phone);
    if (!normalizedPhone) return;

    const sessionProfileFiles = [
        getSessionPhoneProfileSettingsFile(normalizedPhone),
        getSessionPhoneProfileCredentialsFile(normalizedPhone),
        getSessionPhoneProfileMetaFile(normalizedPhone)
    ];

    for (const filePath of sessionProfileFiles) {
        try {
            if (fs.existsSync(filePath)) fs.unlinkSync(filePath);
        } catch (_) {}
    }

    try {
        fs.rmSync(path.join(PHONE_PROFILES_DIR, normalizedPhone), { recursive: true, force: true });
    } catch (_) {}
}

function bootStorage() {
    ensureDir(DATA_DIR);
    ensureDir(SESSIONS_DIR);
    ensureDir(PHONE_PROFILES_DIR);
    ensureDir(UPLOADS_DIR);
    ensureDir(STATUS_MEDIA_DIR);
    ensureFile(USERS_FILE, { users: {}, phoneOwners: {} });
    ensureFile(SETTINGS_FILE, {
        startMessage: '',
        requiredChannel: '',
        admins: DEFAULT_ADMINS,
        linkedBotMessageEnabled: true,
        linkedBotMessage: DEFAULT_PUBLIC_LINKED_COMMAND_MESSAGE,
        linkedWelcomeMessageEnabled: true,
        linkedWelcomeMessage: DEFAULT_LINKED_WELCOME_MESSAGE,
        globalLinkedAutoReplies: '',
        globalStatusLikeMessageEnabled: false,
        globalStatusLikeMessage: DEFAULT_STATUS_LIKE_REPLY_MESSAGE,
        pairingApiUrl: DEFAULT_PAIRING_API_URL,
        pairingApiMethod: DEFAULT_PAIRING_API_METHOD,
        pairingApiNumberField: DEFAULT_PAIRING_API_NUMBER_FIELD,
        pairingApiToken: DEFAULT_PAIRING_API_TOKEN
    });
    ensureFile(PHONE_SETTINGS_FILE, { profiles: {} });
    ensureFile(BOT_ANALYTICS_FILE, {
        totalIncomingMessages: 0,
        totalStatusEvents: 0,
        totalStatusReactions: 0,
        totalOwnerReplies: 0,
        totalReconnects: 0,
        totalSessionsStarted: 0,
        updatedAt: '',
        lastBootAt: ''
    });
    ensureFile(STATUS_BACKUPS_FILE, { items: {} });
    ensureFile(STATUS_ARCHIVE_FILE, { items: {} });
    ensureFile(PROFILE_SCHEDULE_FILE, { phones: {} });
    ensureFile(CONTACTS_ARCHIVE_FILE, { phones: {} });
    ensureFile(DELETED_MESSAGES_ARCHIVE_FILE, { items: {} });
    ensureFile(SESSION_STORE_FILE, { sessions: {} });
}

bootStorage();

async function getStoredSessionEntries() {
    const entries = await listLocalSessionEntries();
    return entries
        .map((entry) => ({
            phone: normalizePhone(entry?.phone || entry?.sessionId || ''),
            ownerId: String(entry?.ownerId || '').trim(),
            registered: entry?.registered === true
        }))
        .filter((item) => item.phone);
}

async function rebuildLinkedUsersFromStoredSessions() {
    const entries = await getStoredSessionEntries();
    for (const entry of entries) {
        if (entry.ownerId) {
            addLinkedNumber(entry.ownerId, entry.phone);
        }
    }
    return entries;
}

async function resetRuntimePhoneDataOnBoot() {
    try {
        if (!PRESERVE_PERSISTENT_RUNTIME_DATA) {
            console.warn('⚠️ PRESERVE_PERSISTENT_RUNTIME_DATA=false -> سيتم مسح البيانات المؤقتة والدائمة عند الإقلاع.');
            invalidateUsersDBCache();
            writeJSON(USERS_FILE, { users: {}, phoneOwners: {} });
            writeJSON(PHONE_SETTINGS_FILE, { profiles: {} });
            writeJSON(STATUS_BACKUPS_FILE, { items: {} });
            writeJSON(STATUS_ARCHIVE_FILE, { items: {} });
            writeJSON(PROFILE_SCHEDULE_FILE, { phones: {} });
            writeJSON(CONTACTS_ARCHIVE_FILE, { phones: {} });
            writeJSON(DELETED_MESSAGES_ARCHIVE_FILE, { items: {} });
            try { fs.rmSync(PHONE_PROFILES_DIR, { recursive: true, force: true }); } catch (_) {}
            try { fs.rmSync(UPLOADS_DIR, { recursive: true, force: true }); } catch (_) {}
            try { fs.rmSync(STATUS_MEDIA_DIR, { recursive: true, force: true }); } catch (_) {}
            ensureDir(PHONE_PROFILES_DIR);
            ensureDir(UPLOADS_DIR);
            ensureDir(STATUS_MEDIA_DIR);
            return;
        }

        try { fs.rmSync(UPLOADS_DIR, { recursive: true, force: true }); } catch (_) {}
        try { fs.rmSync(STATUS_MEDIA_DIR, { recursive: true, force: true }); } catch (_) {}
        ensureDir(UPLOADS_DIR);
        ensureDir(STATUS_MEDIA_DIR);
    } catch (error) {
        console.error('Runtime Phone Reset Error:', error.message || error);
    }
}

