async function openStatusArchiveItem(ctx, phone, statusId, source = 'all') {
    const entry = getStatusArchiveEntry(phone, statusId);
    if (!entry) return safeReply(ctx, '❌ لم أجد هذه الحالة أو تم حذفها من الأرشيف.');
    const caption = buildStatusPreviewCaption(entry);
    const buttons = buildStatusEntryButtons(phone, entry, source);
    if (entry.kind === 'text') return safeReply(ctx, caption, buttons);
    const buffer = await getStatusMediaBuffer(entry);
    if (!buffer?.length) return safeReply(ctx, '❌ ملف الحالة غير موجود حالياً على الخادم.');
    if (entry.kind === 'image') return ctx.replyWithPhoto({ source: buffer }, { caption: caption.slice(0, 1024), ...buttons });
    if (entry.kind === 'video') return ctx.replyWithVideo({ source: buffer }, { caption: caption.slice(0, 1024), ...buttons });
    if (entry.kind === 'audio') {
        await ctx.replyWithAudio({ source: buffer }, buttons);
        return safeReply(ctx, caption, buttons);
    }
    await ctx.replyWithDocument({ source: buffer, filename: entry.fileName || 'status.bin' }, buttons);
    return safeReply(ctx, caption, buttons);
}

async function sendStatusArchiveDownload(ctx, phone, statusId) {
    const entry = getStatusArchiveEntry(phone, statusId);
    if (!entry) return safeReply(ctx, '❌ لم أجد هذه الحالة أو تم حذفها.');
    if (entry.kind === 'text') return safeReply(ctx, `📋 نص الحالة جاهز للنسخ:

${String(entry.text || entry.caption || '').trim() || 'لا يوجد نص.'}`);
    const buffer = await getStatusMediaBuffer(entry);
    if (!buffer?.length) return safeReply(ctx, '❌ ملف الحالة غير متوفر للتنزيل حالياً.');
    const caption = `👤 صاحب الحالة: ${formatStatusArchiveOwner(entry)}`;
    if (entry.kind === 'image') return ctx.replyWithPhoto({ source: buffer }, { caption });
    if (entry.kind === 'video') return ctx.replyWithVideo({ source: buffer }, { caption });
    if (entry.kind === 'audio') return ctx.replyWithAudio({ source: buffer }, { caption });
    return ctx.replyWithDocument({ source: buffer, filename: entry.fileName || 'status.bin' }, { caption });
}


